    prefixMod[0] = -1;
    long long sum = 0;
    vector<pair<long long, long long>> segments;

    for (long long i = 0; i < nums.size(); ++i) {
        sum += nums[i];
        long long mod = (sum % k + k) % k;
        if (prefixMod.find(mod) != prefixMod.end()) {
            long long prev = prefixMod[mod];
            segments.emplace_back(prev + 1, i);
        }
        prefixMod[mod] = i;
